onRecordDelete(n=>{if($os.getenv("ENVIRONMENT")!=="dev"){let e=n.record.get("repo"),o=n.record.get("name"),t=$os.getenv("RUNNER_URL");$os.exec("sudo","a2dissite",e,`${e}-le-ssl`).run(),$os.exec("sudo","rm",`/etc/apache2/sites-available/${e}.conf`,`/etc/apache2/sites-available/${e}-le-ssl.conf`).run(),$os.exec("docker","stop",`${o}-container`).run(),$os.exec("docker","rm",`${o}-container`).run(),$os.exec("docker","rmi",`${o}-image`).run(),$os.exec("certbot","delete","--cert-name",`${o}.${t}`,"--non-interactive").run(),$os.exec("apache2ctl","restart").run()}else console.log("Host metadata cannot be deleted in a dev environment.");n.next()},"hosts");
